    t[0].field0.value_ = 0
    t[0].field0.tt_ = 0
    stack[0].value_ = ptr_u64(t)
    stack[0].tt_ = 69
    stack[1].value_ = 88
    stack[1].tt_ = 3
    ctx.exit_kind = 99
  end,
  function(ctx)
    local t = ffi.cast("SponTestTable *", ffi.cast("uintptr_t", ctx.scratch[0].value_))
    assert_eq(tonumber(ctx.exit_kind), 0, "SETFIELD exit")
    assert_eq(tonumber(t[0].field0.value_), 88, "SETFIELD value")
    assert_eq(tonumber(t[0].field0.tt_), 3, "SETFIELD tag")
  end)

local self_stencil = lower_native({ { op = "SELF", a = 1, b = 0, c = 2 } }, field_facts(false))
run_native(self_stencil,
  function(buf, f) patch_payloads(buf, f, field_payload) end,
  function(ctx, stack)
    local t = ffi.new("SponTestTable[1]")
    table_keepalive.self = t
    t[0].shape_id = field_payload.shape_id
    t[0].metatable = nil
    t[0].field0.value_ = 0xfeed
    t[0].field0.tt_ = 3
    stack[0].value_ = ptr_u64(t)
    stack[0].tt_ = 69
    ctx.exit_kind = 99
  end,
  function(ctx, stack)
    assert_eq(tonumber(ctx.exit_kind), 0, "SELF exit")
    assert_eq(tonumber(stack[1].value_), 0xfeed, "SELF method value")
    assert_eq(tonumber(stack[1].tt_), 3, "SELF method tag")
    assert_eq(tonumber(stack[2].tt_), 69, "SELF receiver tag")
  end)

local unsupported = SSA.compile({ { op = "GETUPVAL", a = 0, b = 0 } }, {})
assert_true(not unsupported.ok, "GETUPVAL must remain explicit missing coverage")
local unsupported_table = SSA.compile({ { op = "GETTABLE", a = 0, b = 0, c = 1 } }, {})
assert_true(not unsupported_table.ok, "GETTABLE without table/array payload facts must remain explicit missing coverage")
local unsupported_pow = SSA.compile({ { op = "POW", a = 0, b = 0, c = 1 } }, { Facts.fact("type", Facts.slot("R0"), "is_i64", true), Facts.fact("type", Facts.slot("R1"), "is_i64", true) })
assert_true(not unsupported_pow.ok, "POW must remain unsupported until exact Lua pow semantics exist")

print("ok - SpongeJIT native stencil bytes execute")

#!/usr/bin/env luajit

package.path = "./?.lua;./?/init.lua;./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local bit = require("bit")
local Materialize = require("src.materialize_native_x64")
local Facts = require("src.facts")
local Sig = require("src.fact_signature")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

ffi.cdef[[
typedef unsigned int uint32_t;
typedef unsigned short uint16_t;
typedef int int32_t;
typedef unsigned long long uint64_t;
typedef uint64_t SponFactSig;
typedef uint32_t SponStencilId;

typedef struct SponTValueABI {
  unsigned long long value_;
  unsigned char tt_;
} SponTValueABI;
typedef struct SponExecCtx {
  void *stack;
  SponTValueABI *k;
  SponTValueABI scratch[256];
  uint32_t exit_kind;
  uint32_t exit_pc;
  uint32_t exit_op_idx;
  uint32_t exit_hole;
} SponExecCtx;
typedef struct SponTestTable {
  uint32_t shape_id;
  uint32_t pad0;
  void *metatable;
  SponTValueABI field0;
  SponTValueABI field1;
} SponTestTable;

typedef struct {
  SponStencilId stencil_id;
  uint32_t pc_start;
  uint32_t pc_end;
} SponStencilChoice;

typedef struct {
  uint64_t pattern_probes;
  uint64_t candidate_checks;
  uint32_t choices;
  uint32_t status;
  uint32_t covered_end;
  uint32_t first_uncovered_pc;
  uint32_t no_candidate_opcode;
} SponSelectStats;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t role_kind;
  uint16_t op_idx;
  int32_t role_arg;
  int32_t addend;
} SponDataReloc;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t edge_kind;
  uint16_t endpoint_index;
  int32_t target_delta;
} SponControlReloc;

typedef struct {
  uint16_t op_idx;
  uint8_t logical_slot;
  uint8_t field_kind;
} SponSlotMapEntry;

typedef struct {
  SponStencilId stencil_id;
  uint32_t offset;
  uint32_t size;
  uint32_t endpoint_start;
  uint32_t data_reloc_start;
  uint32_t control_reloc_start;
  uint32_t slotmap_start;
  uint32_t projection_start;
  uint32_t dependency_start;
  uint16_t len;
  uint16_t n_endpoints;
  uint16_t n_data_relocs;
  uint16_t n_control_relocs;
  uint16_t n_slotmaps;
  uint16_t n_projections;
  uint16_t n_dependencies;
  uint16_t flags;
  uint16_t physical_abi;
  uint16_t reserved;
  uint64_t pattern_key;
  SponFactSig selector_sig;
  SponFactSig required_sig;
  SponFactSig checked_sig;
  SponFactSig produced_sig;
  SponFactSig killed_sig;
} SponStencilDesc;

uint32_t spon_bank_stencil_count(void);
uint32_t spon_bank_pattern_count(void);
const SponStencilDesc *spon_get_stencil(SponStencilId id);
const unsigned char *spon_stencil_data(SponStencilId id);
const SponDataReloc *spon_stencil_data_relocs(SponStencilId id, uint32_t *out_n);
const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n);
const SponStencilChoice *spon_select_flow_flags_slots_stats(const uint32_t *bc, uint32_t start, uint32_t end,
                                                           SponFactSig entry_sig, SponFactSig observed_sig,
                                                           uint16_t required_stencil_flags,
                                                           const SponSlotMapEntry *actual_slots,
                                                           uint32_t n_actual_slots,
                                                           uint32_t *out_n,
                                                           SponSelectStats *stats);
]]

local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
do
  local f = io.open(bank_path, "rb")
  assert_true(f ~= nil, "missing generated L1 bank: run cd experiments/lua_interpreter_vm/spongejit && make stencils && make bank")
  if f then f:close() end
end

local bank = ffi.load(bank_path)
assert_true(bank.spon_bank_stencil_count() > 0, "empty stencil bank")
assert_true(bank.spon_bank_pattern_count() > 0, "empty pattern bank")

local function bytes_to_hex(p, n)
  local out = {}
  for i = 0, n - 1 do out[#out + 1] = string.format("%02x", tonumber(p[i])) end
  return table.concat(out)
end

local function c_data_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_data_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      role_kind = tonumber(p[i].role_kind),
      op_idx = tonumber(p[i].op_idx),
      role_arg = tonumber(p[i].role_arg),
      addend = tonumber(p[i].addend),
    }
  end
  return out
end

local function c_control_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_control_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      edge_kind = tonumber(p[i].edge_kind),
      endpoint_index = tonumber(p[i].endpoint_index),
      target_delta = tonumber(p[i].target_delta),
    }
  end
  return out
end

local function from_bank(id)
  local d = bank.spon_get_stencil(id)
  assert_true(d ~= nil, "missing stencil descriptor " .. tostring(id))
  assert_true(bit.band(tonumber(d.flags), 10) == 10, "selected stencil is not exact native: " .. tostring(id))
  assert_true(tonumber(d.size) > 0, "selected stencil has no native bytes: " .. tostring(id))
  local data = bank.spon_stencil_data(id)
  assert_true(data ~= nil, "spon_stencil_data returned NULL: " .. tostring(id))
  return {
    stencil_id = tonumber(d.stencil_id),
    executable = true,
    flags = tonumber(d.flags),
    code_size = tonumber(d.size),
    code_hex = bytes_to_hex(data, tonumber(d.size)),
    data_relocs = c_data_relocs(id),
    control_relocs = c_control_relocs(id),
  }
end

local function has_edge(st, edge_kind)
  for _, cr in ipairs(st.control_relocs or {}) do if cr.edge_kind == edge_kind then return true end end
  return false
end

local function read_i64(stack, slot)
  return tonumber(ffi.cast("int64_t *", stack)[(slot or 0) * 2])
end

local function read_f64(stack, slot)
  return tonumber(ffi.cast("double *", stack)[(slot or 0) * 2])
end

local function ptr_u64(p)
  return ffi.cast("uint64_t", ffi.cast("uintptr_t", p))
end

local function sig_u64(facts)
  local sig = Sig.encode(facts)
  return ffi.new("uint64_t", sig.hi or 0) * 0x100000000ULL + ffi.new("uint64_t", sig.lo or 0)
end

local function field_facts(include_barrier)
  local xs = {
    Facts.fact("type", Facts.slot("R0"), "is_table", true),
    Facts.fact("shape", Facts.slot("R0"), "shape_known", true),
    Facts.fact("shape", Facts.slot("R0"), "shape_eq", "shape:test"),
    Facts.fact("metatable", Facts.slot("R0"), "metatable_absent", true),
    Facts.fact("constant", Facts.value("K2"), "key_const", true),
    Facts.fact("shape", Facts.value("K2"), "field_offset", "shape:test"),
  }
  if include_barrier then xs[#xs + 1] = Facts.fact("gc", Facts.global_subject(), "barrier_clean", true) end
  return xs
end

local FIELD_PAYLOAD = {
  shape_offset = ffi.offsetof("SponTestTable", "shape_id"),
  shape_id = 0x1234abcd,
  metatable_offset = ffi.offsetof("SponTestTable", "metatable"),
  field_offset = ffi.offsetof("SponTestTable", "field0"),
}
local table_keepalive = {}

local FIELD_KIND = { a = 1, b = 2, c = 3, dest = 4, aux = 5 }

local function actual_slot_entries(ops)
  local xs = {}
  for pc, op in ipairs(ops or {}) do
    for field, kind in pairs(FIELD_KIND) do
      local slot = op[field]
      if slot == nil and op.op == "SELF" and field == "aux" and tonumber(op.a) then slot = tonumber(op.a) + 1 end
      if slot ~= nil and tonumber(slot) then
        xs[#xs + 1] = { op_idx = pc - 1, logical_slot = tonumber(slot), field_kind = kind }
      end
    end
  end
  local arr = ffi.new("SponSlotMapEntry[?]", #xs)
  for i, x in ipairs(xs) do
    arr[i - 1].op_idx = x.op_idx
    arr[i - 1].logical_slot = x.logical_slot
    arr[i - 1].field_kind = x.field_kind
  end
  return arr, #xs
end

local function select_entries(ops, entry_sig, observed_sig)
  local bc = ffi.new("uint32_t[?]", #ops)
  for i, op in ipairs(ops) do bc[i - 1] = assert(Constants.Op[op.op], "unknown opcode " .. tostring(op.op)) end
  local slots, nslots = actual_slot_entries(ops)
  local out_n = ffi.new("uint32_t[1]")
  local stats = ffi.new("SponSelectStats")
  local choices = bank.spon_select_flow_flags_slots_stats(bc, 0, #ops, entry_sig or 0, observed_sig or 0, 10, slots, nslots, out_n, stats)
  local n = tonumber(out_n[0])
  assert_true(n > 0, "selector returned no choices")
  assert_eq(tonumber(stats.status), 0, "selector did not report full exact coverage")
  local entries = {}
  local pc = 0
  for i = 0, n - 1 do
    local ch = choices[i]
    assert_eq(tonumber(ch.pc_start), pc, "non-contiguous selector choice")
    pc = tonumber(ch.pc_end)
    local st = from_bank(tonumber(ch.stencil_id))
    local slice = {}
    for j = tonumber(ch.pc_start) + 1, tonumber(ch.pc_end) do slice[#slice + 1] = ops[j] end
    entries[#entries + 1] = { stencil = st, ops = slice }
  end
  assert_eq(pc, #ops, "selector did not cover full span")
  assert_eq(tonumber(stats.covered_end), #ops, "selector stats covered_end")
  return entries
end

local function run_image(img, setup, check)
  local mem, n = assert(Materialize.alloc_executable(img.bytes))
  local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
  local stack = ffi.new("SponTValueABI[8]")
  local k = ffi.new("SponTValueABI[8]")
  local ctx = ffi.new("SponExecCtx")
  ctx.stack = stack
  ctx.k = k
  setup(ctx, stack, k)
  fn(ctx)
  check(ctx, stack, k)
  Materialize.free_executable(mem, n)
end

-- End-to-end generated bank path:
-- C selector -> SponStencilChoice[] -> C descriptors/bytes/relocs -> Lua CLP
-- materializer -> mmap -> execute linked image.
do
  local ops = {
    { op = "ADDI", a = 0, b = 0, c = 1 },
    { op = "ADDI", a = 0, b = 0, c = 2 },
    { op = "ADDI", a = 0, b = 0, c = 3 },
    { op = "ADDI", a = 0, b = 0, c = 4 },
    { op = "ADDI", a = 0, b = 0, c = 5 },
  }
  local i64_r0 = 1
  local entries = select_entries(ops, i64_r0, i64_r0)
  assert_true(#entries >= 2, "five-op span should require at least two max-arity choices")
  assert_true(has_edge(entries[1].stencil, 1), "first bank stencil missing fallthrough edge")
  assert_true(has_edge(entries[1].stencil, 2), "first bank stencil missing guard edge")
  local img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, "bank materialization failed")

  run_image(img,
    function(ctx, stack)
      stack[0].value_ = 0
      stack[0].tt_ = 3 -- LUA_VNUMINT
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 0, "bank-linked ADDI exit")
      assert_eq(tonumber(stack[0].value_), 15, "bank-linked ADDI result")
      assert_eq(tonumber(stack[0].tt_), 3, "bank-linked ADDI tag")
    end)

  run_image(img,
    function(ctx, stack)
      stack[0].value_ = 0
      stack[0].tt_ = 0
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 1, "bank-linked guard exit")
      assert_eq(tonumber(stack[0].value_), 0, "guard failure must not run linked span")
    end)
end

-- Fact-specialized exact integer division/modulo stencils are selected from
-- the generated bank and execute real native semantics, including Lua floor
-- division/modulo behavior for negative operands.
do
  local i64_r0 = 1
  for _, case in ipairs({
    { op = "IDIV", expected = 1, tag = 3 },
    { op = "MOD", expected = 0, tag = 3 },
    { op = "DIV", expected_f64 = 1.0, tag = 19 },
  }) do
    local ops = { { op = case.op, a = 0, b = 0, c = 0 } }
    local entries = select_entries(ops, i64_r0, 0)
    local img = Materialize.materialize(entries)
    assert_true(img.ok and img.code_size > 0, case.op .. " materialization failed")
    run_image(img,
      function(ctx, stack)
        stack[0].value_ = ffi.cast("uint64_t", -7)
        stack[0].tt_ = 3
        ctx.exit_kind = 99
      end,
      function(ctx, stack)
        assert_eq(tonumber(ctx.exit_kind), 0, case.op .. " exit")
        assert_eq(tonumber(stack[0].tt_), case.tag, case.op .. " tag")
        if case.expected_f64 then
          assert_true(math.abs(read_f64(stack, 0) - case.expected_f64) < 1e-12, case.op .. " f64 result")
        else
          assert_eq(read_i64(stack, 0), case.expected, case.op .. " i64 result")
        end
      end)
  end
end

-- K-operand arithmetic stencils patch constant values explicitly; the constant
-- pool index is not mistaken for the integer payload.
do
  local CONST_I64 = ffi.new("uint64_t", 0x02000000) * 0x100000000ULL
  local I64_R0_AND_CONST = CONST_I64 + 1
  for _, case in ipairs({
    { op = "IDIVK", const = 3, expected = -3, tag = 3 },
    { op = "MODK", const = 3, expected = 2, tag = 3 },
    { op = "DIVK", const = 2, expected_f64 = -3.5, tag = 19 },
  }) do
    local ops = { { op = case.op, a = 0, b = 0, c = 0 } }
    local entries = select_entries(ops, I64_R0_AND_CONST, 0)
    entries[1].const_i64s = { [0] = case.const }
    local img = Materialize.materialize(entries)
    assert_true(img.ok and img.code_size > 0, case.op .. " materialization failed")
    run_image(img,
      function(ctx, stack)
        stack[0].value_ = ffi.cast("uint64_t", -7)
        stack[0].tt_ = 3
        ctx.exit_kind = 99
      end,
      function(ctx, stack)
        assert_eq(tonumber(ctx.exit_kind), 0, case.op .. " exit")
        assert_eq(tonumber(stack[0].tt_), case.tag, case.op .. " tag")
        if case.expected_f64 then
          assert_true(math.abs(read_f64(stack, 0) - case.expected_f64) < 1e-12, case.op .. " f64 result")
        else
          assert_eq(read_i64(stack, 0), case.expected, case.op .. " i64 result")
        end
      end)
  end
end

-- Newly modeled structural/dynamic VM boundary opcodes are selected from the
-- generated bank and materialize to exact boundary exits, not hidden fallbacks.
for _, bop in ipairs({
  { op = "LEN", a = 0, b = 1 },
  { op = "MMBIN", a = 0, b = 0, c = 0 },
  { op = "CLOSE", a = 0 },
  { op = "NEWTABLE", a = 0, b = 0, c = 0 },
  { op = "CLOSURE", a = 0, bx = 0 },
  { op = "VARARGPREP", a = 0 },
  { op = "EXTRAARG", ax = 0 },
}) do
  local entries = select_entries({ bop }, 0, 0)
  assert_eq(#entries, 1, bop.op .. " boundary selection count")
  assert_true(has_edge(entries[1].stencil, 3), bop.op .. " missing boundary edge")
  local img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, bop.op .. " boundary materialization failed")
  run_image(img,
    function(ctx) ctx.exit_kind = 99 end,
    function(ctx) assert_eq(tonumber(ctx.exit_kind), 2, bop.op .. " boundary exit") end)
end

-- Fact-specialized raw field/SELF stencils are selected from the generated
-- bank and execute real guarded native semantics when payload bindings are supplied.
do
  local get_ops = { { op = "GETFIELD", a = 1, b = 0, c = 2 } }
  local entries = select_entries(get_ops, sig_u64(field_facts(false)), 0)
  assert_eq(#entries, 1, "GETFIELD selection count")
  entries[1].payloads = FIELD_PAYLOAD
  entries[1].slot_bindings = { [0] = 1, [1] = 0 }
  local img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, "GETFIELD materialization failed")
  run_image(img,
    function(ctx, stack)
      local t = ffi.new("SponTestTable[1]")
      table_keepalive.bank_getfield = t
      t[0].shape_id = FIELD_PAYLOAD.shape_id
      t[0].metatable = nil
      t[0].field0.value_ = 123
      t[0].field0.tt_ = 3
      stack[0].value_ = ptr_u64(t)
      stack[0].tt_ = 69
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 0, "bank GETFIELD exit")
      assert_eq(tonumber(stack[1].value_), 123, "bank GETFIELD value")
      assert_eq(tonumber(stack[1].tt_), 3, "bank GETFIELD tag")
    end)

  local set_ops = { { op = "SETFIELD", a = 0, b = 2, c = 0 } }
  entries = select_entries(set_ops, sig_u64(field_facts(true)), 0)
  assert_eq(#entries, 1, "SETFIELD selection count")
  entries[1].payloads = FIELD_PAYLOAD
  entries[1].slot_bindings = { [0] = 0 }
  img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, "SETFIELD materialization failed")
  run_image(img,
    function(ctx, stack)
      local t = ffi.new("SponTestTable[1]")
      table_keepalive.bank_setfield = t
      ctx.scratch[0].value_ = ptr_u64(t)
      t[0].shape_id = FIELD_PAYLOAD.shape_id
      t[0].metatable = nil
      stack[0].value_ = ptr_u64(t)
      stack[0].tt_ = 69
      ctx.exit_kind = 99
    end,
    function(ctx)
      local t = ffi.cast("SponTestTable *", ffi.cast("uintptr_t", ctx.scratch[0].value_))
      assert_eq(tonumber(ctx.exit_kind), 0, "bank SETFIELD exit")
      assert_eq(tostring(t[0].field0.value_), tostring(ctx.scratch[0].value_), "bank SETFIELD value")
      assert_eq(tonumber(t[0].field0.tt_), 69, "bank SETFIELD tag")
    end)

  local self_ops = { { op = "SELF", a = 1, b = 0, c = 2 } }
  entries = select_entries(self_ops, sig_u64(field_facts(false)), 0)
  assert_eq(#entries, 1, "SELF selection count")
  entries[1].payloads = FIELD_PAYLOAD
  entries[1].slot_bindings = { [0] = 1, [1] = 0, [2] = 2 }
  img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, "SELF materialization failed")
  run_image(img,
    function(ctx, stack)
      local t = ffi.new("SponTestTable[1]")
      table_keepalive.bank_self = t
      t[0].shape_id = FIELD_PAYLOAD.shape_id
      t[0].metatable = nil
      t[0].field0.value_ = 789
      t[0].field0.tt_ = 3
      stack[0].value_ = ptr_u64(t)
      stack[0].tt_ = 69
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 0, "bank SELF exit")
      assert_eq(tonumber(stack[1].value_), 789, "bank SELF method")
      assert_eq(tonumber(stack[2].tt_), 69, "bank SELF receiver")
    end)
end

-- Missing semantic coverage is explicit; the selector must not synthesize a hidden L0 fallback.
do
  local ops = { { op = "GETUPVAL", a = 0, b = 0 } }
  local bc = ffi.new("uint32_t[1]")
  bc[0] = Constants.Op.GETUPVAL
  local slots, nslots = actual_slot_entries(ops)
  local out_n = ffi.new("uint32_t[1]")
  local stats = ffi.new("SponSelectStats")
